#### Step 4: Add `copy_env_to_scope` helper — `eval.c3` (replace `deep_copy_env`)

```c3
/// Copy an env chain to interp.current_scope (which should be set to a closure's env_scope).
/// Uses copy_to_parent for each binding value — values are allocated in current_scope.
/// Stops at global_env (already in root). Skips persistent env nodes (mutable boxes in root).
fn Env* copy_env_to_scope(Env* env, Interp* interp, usz depth = 0) {
    if (env == null || env == interp.global_env) return env;
    if (depth >= 256) return null;
    if (env.persistent) {
        env.parent = copy_env_to_scope(env.parent, interp, depth + 1);
        return env;
    }

    Env* new_env = make_env(interp, null);  // Allocated in current_scope (= env_scope)
    new_env.bindings = (Binding*)mem::malloc(Binding.sizeof * env.binding_count);
    new_env.capacity = env.binding_count;
    new_env.binding_count = env.binding_count;
    for (usz i = 0; i < env.binding_count; i++) {
        new_env.bindings[i].name = env.bindings[i].name;
        new_env.bindings[i].value = copy_to_parent(
            env.bindings[i].value, interp, interp.current_frame);
    }
    new_env.parent = copy_env_to_scope(env.parent, interp, depth + 1);
    if (env.hash_table != null) new_env.build_hash_table();
    main::scope_register_dtor(interp.current_scope, (void*)new_env, &scope_dtor_env);
    return new_env;
}
```

This is structurally identical to `deep_copy_env` but:
- Does NOT switch to root_scope/root_region (caller manages current_scope)
- Uses `copy_to_parent` for values — which now handles CLOSURE via refcount sharing

