| `runtime::make_prim(&runtime::rt_mod)` | `aot::lookup_prim("%")` |
| `runtime::make_prim(&runtime::rt_eq)` | `aot::lookup_prim("=")` |
| `runtime::make_prim(&runtime::rt_lt)` | `aot::lookup_prim("<")` |
| `runtime::make_prim(&runtime::rt_gt)` | `aot::lookup_prim(">")` |
| `runtime::make_prim(&runtime::rt_le)` | `aot::lookup_prim("<=")` |
| `runtime::make_prim(&runtime::rt_ge)` | `aot::lookup_prim(">=")` |
| `runtime::make_prim_unary(&runtime::rt_car)` | `aot::lookup_prim("car")` |
| `runtime::make_prim_unary(&runtime::rt_cdr)` | `aot::lookup_prim("cdr")` |
| `runtime::make_prim(&runtime::rt_cons_prim)` | `aot::lookup_prim("cons")` |
